// client/src/pages/HomePage.js
import React, { useEffect, useState } from 'react';
import { useUser } from '../context/UserContext';
import { useNavigate } from 'react-router-dom';
import ResourceBar from '../components/ResourceBar';
import Loading from '../components/Loading';
import { FishingIcon, HuntingIcon, CompassIcon } from '../components/Icons';

const HomePage = () => {
  const { user, loading, fetchCats, cats } = useUser();
  const [activeCat, setActiveCat] = useState(null);
  const navigate = useNavigate();

  // Получение кошек пользователя при загрузке страницы
  useEffect(() => {
    if (user) {
      fetchCats();
    }
  }, [user, fetchCats]);

  // Выбор активной кошки (если есть)
  useEffect(() => {
    if (cats && cats.length > 0) {
      setActiveCat(cats[0]);
    }
  }, [cats]);

  if (loading || !user) {
    return <Loading />;
  }

  // Переход к выбору кошки, если пользователь хочет сменить активную
  const handleChangeCat = () => {
    navigate('/cats');
  };

  // Переход к исследованию с выбранной кошкой
  const handleExplore = () => {
    if (activeCat) {
      navigate('/explore', { state: { selectedCat: activeCat } });
    }
  };

  return (
    <div className="pb-16">
      <ResourceBar />

      <div className="pt-16 px-4">
        <h1 className="text-2xl font-bold mb-4">Кошачья Империя</h1>

        {/* Информация об активной кошке */}
        {activeCat ? (
          <div className="bg-white rounded-lg shadow-md p-4 mb-6">
            <div className="flex justify-between items-start">
              <div>
                <h2 className="text-lg font-bold">{activeCat.name}</h2>
                <p className="text-sm text-gray-600">Уровень {activeCat.level}</p>
              </div>
              <button 
                onClick={handleChangeCat}
                className="text-xs text-cat-secondary"
              >
                Сменить
              </button>
            </div>

            <div className="mt-3">
              <div className="bg-gray-200 h-2 rounded-full w-full mt-2">
                <div 
                  className="bg-cat-primary h-2 rounded-full" 
                  style={{ width: `${(activeCat.experience % 100)}%` }}
                ></div>
              </div>
              <p className="text-xs text-right mt-1">
                {activeCat.experience % 100}/100 опыта до следующего уровня
              </p>
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-lg shadow-md p-4 mb-6">
            <p>У вас пока нет кошек. Отправляйтесь на исследование, чтобы найти кошку!</p>
          </div>
        )}

        {/* Действия */}
        <h2 className="text-xl font-bold mb-3">Действия</h2>
        <div className="grid grid-cols-2 gap-4 mb-6">
          <button 
            onClick={() => navigate('/village')}
            className="bg-white rounded-lg shadow-md p-4 flex flex-col items-center"
          >
            <div className="w-12 h-12 bg-cat-light rounded-full flex items-center justify-center mb-2">
              <img src="/assets/ui/village.png" alt="Поселение" className="w-8 h-8" />
            </div>
            <span className="font-medium">Поселение</span>
          </button>

          <button 
            onClick={handleExplore}
            className="bg-white rounded-lg shadow-md p-4 flex flex-col items-center"
          >
            <div className="w-12 h-12 bg-cat-light rounded-full flex items-center justify-center mb-2">
              <CompassIcon className="w-8 h-8 text-cat-primary" />
            </div>
            <span className="font-medium">Исследовать</span>
          </button>

          <button 
            onClick={() => navigate('/cats')}
            className="bg-white rounded-lg shadow-md p-4 flex flex-col items-center"
          >
            <div className="w-12 h-12 bg-cat-light rounded-full flex items-center justify-center mb-2">
              <img src="/assets/ui/cats.png" alt="Кошки" className="w-8 h-8" />
            </div>
            <span className="font-medium">Кошки</span>
          </button>

          <button 
            onClick={() => navigate('/tasks')}
            className="bg-white rounded-lg shadow-md p-4 flex flex-col items-center"
          >
            <div className="w-12 h-12 bg-cat-light rounded-full flex items-center justify-center mb-2">
              <img src="/assets/ui/tasks.png" alt="Задания" className="w-8 h-8" />
            </div>
            <span className="font-medium">Задания</span>
          </button>
        </div>

        {/* Быстрые действия */}
        {activeCat && (
          <>
            <h2 className="text-xl font-bold mb-3">Быстрые действия</h2>
            <div className="grid grid-cols-2 gap-4">
              <button 
                className="bg-white rounded-lg shadow-md p-3 flex items-center"
                onClick={() => navigate('/explore', { state: { selectedCat: activeCat, preselectedAction: 'fishing' } })}
              >
                <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center mr-3">
                  <FishingIcon className="w-6 h-6 text-blue-500" />
                </div>
                <div className="text-left">
                  <span className="font-medium">Рыбалка</span>
                  <p className="text-xs text-gray-600">+{5 + Math.floor(activeCat.stats.fishing * 0.5)} рыбы</p>
                </div>
              </button>

              <button 
                className="bg-white rounded-lg shadow-md p-3 flex items-center"
                onClick={() => navigate('/explore', { state: { selectedCat: activeCat, preselectedAction: 'hunting' } })}
              >
                <div className="w-10 h-10 bg-green-100 rounded-full flex items-center justify-center mr-3">
                  <HuntingIcon className="w-6 h-6 text-green-500" />
                </div>
                <div className="text-left">
                  <span className="font-medium">Охота</span>
                  <p className="text-xs text-gray-600">+{3 + Math.floor(activeCat.stats.hunting * 0.5)} клубков</p>
                </div>
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

export default HomePage;
